@import url('https://fonts.googleapis.com/css2?family=Pretendard:wght@400;600;700;800;900&display=swap');
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700;800;900&display=swap');

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg: #0a0a0a;
  --surface: #141414;
  --surface2: #1e1e1e;
  --border: #2a2a2a;
  --text: #ffffff;
  --text-muted: #888888;
  --accent: #f97316;
  --accent2: #3b82f6;
  --radius: 20px;
}

html { scroll-behavior: smooth; }

body {
  background: var(--bg);
  color: var(--text);
  font-family: 'Inter', 'Pretendard', -apple-system, sans-serif;
  line-height: 1.6;
  overflow-x: hidden;
}

/* NAV */
nav {
  position: fixed;
  top: 0;
  width: 100%;
  z-index: 100;
  padding: 16px 40px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: rgba(10,10,10,0.8);
  backdrop-filter: blur(20px);
  border-bottom: 1px solid var(--border);
}

.nav-logo {
  font-size: 22px;
  font-weight: 900;
  letter-spacing: -0.5px;
}

.nav-logo span { color: var(--accent); }

.nav-links {
  display: flex;
  gap: 32px;
  list-style: none;
}

.nav-links a {
  color: var(--text-muted);
  text-decoration: none;
  font-size: 14px;
  font-weight: 600;
  transition: color 0.2s;
}

.nav-links a:hover { color: var(--text); }

.nav-cta {
  background: var(--accent);
  color: #000;
  border: none;
  padding: 10px 22px;
  border-radius: 50px;
  font-size: 14px;
  font-weight: 700;
  cursor: pointer;
  transition: opacity 0.2s, transform 0.2s;
}

.nav-cta:hover { opacity: 0.85; transform: scale(1.03); }

/* HERO */
.hero {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  padding: 120px 24px 80px;
  position: relative;
  overflow: hidden;
}

.hero::before {
  content: '';
  position: absolute;
  top: -200px;
  left: 50%;
  transform: translateX(-50%);
  width: 800px;
  height: 800px;
  background: radial-gradient(circle, rgba(249,115,22,0.15) 0%, transparent 70%);
  pointer-events: none;
}

.hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  background: rgba(249,115,22,0.12);
  border: 1px solid rgba(249,115,22,0.3);
  color: var(--accent);
  padding: 6px 16px;
  border-radius: 50px;
  font-size: 13px;
  font-weight: 600;
  margin-bottom: 32px;
}

.hero-badge::before {
  content: '';
  width: 6px;
  height: 6px;
  background: var(--accent);
  border-radius: 50%;
  animation: pulse 1.5s infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.3; }
}

.hero h1 {
  font-size: clamp(28px, 9vw, 96px);
  font-weight: 900;
  letter-spacing: -3px;
  line-height: 1.05;
  margin-bottom: 24px;
}

.hero h1 .highlight {
  color: var(--accent);
}

.hero p {
  font-size: clamp(16px, 2vw, 20px);
  color: var(--text-muted);
  max-width: 540px;
  margin: 0 auto 48px;
  line-height: 1.7;
}

.hero-buttons {
  display: flex;
  gap: 16px;
  justify-content: center;
  flex-wrap: wrap;
}

.btn-primary {
  background: var(--accent);
  color: #000;
  border: none;
  padding: 16px 36px;
  border-radius: 50px;
  font-size: 16px;
  font-weight: 700;
  cursor: pointer;
  text-decoration: none;
  display: inline-block;
  transition: opacity 0.2s, transform 0.2s;
}

.btn-primary:hover { opacity: 0.85; transform: translateY(-2px); }

.btn-secondary {
  background: var(--surface2);
  color: var(--text);
  border: 1px solid var(--border);
  padding: 16px 36px;
  border-radius: 50px;
  font-size: 16px;
  font-weight: 700;
  cursor: pointer;
  text-decoration: none;
  display: inline-block;
  transition: background 0.2s, transform 0.2s;
}

.btn-secondary:hover { background: var(--surface); transform: translateY(-2px); }

/* STATS */
.stats {
  padding: 80px 24px;
  max-width: 1100px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 24px;
}

.stat-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 36px 32px;
  transition: transform 0.2s, border-color 0.2s;
}

.stat-card:hover {
  transform: translateY(-4px);
  border-color: var(--accent);
}

.stat-number {
  font-size: 42px;
  font-weight: 900;
  letter-spacing: -2px;
  color: var(--accent);
}

.stat-label {
  font-size: 14px;
  color: var(--text-muted);
  margin-top: 8px;
  font-weight: 600;
}

/* SECTION */
.section {
  padding: 100px 24px;
  max-width: 1100px;
  margin: 0 auto;
}

.section-tag {
  font-size: 13px;
  font-weight: 700;
  color: var(--accent);
  text-transform: uppercase;
  letter-spacing: 2px;
  margin-bottom: 16px;
}

.section-title {
  font-size: clamp(32px, 4vw, 52px);
  font-weight: 900;
  letter-spacing: -2px;
  line-height: 1.1;
  margin-bottom: 16px;
}

.section-desc {
  font-size: 17px;
  color: var(--text-muted);
  max-width: 500px;
  line-height: 1.7;
  margin-bottom: 48px;
}

/* EVENTS */
.events-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 20px;
}

.event-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 32px;
  position: relative;
  overflow: hidden;
  transition: transform 0.2s, border-color 0.2s;
  cursor: pointer;
}

.event-card:hover {
  transform: translateY(-4px);
  border-color: var(--accent);
}

.event-card::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 3px;
  background: var(--accent);
}

.event-card.blue::before { background: var(--accent2); }
.event-card.green::before { background: #22c55e; }

.event-month {
  font-size: 12px;
  font-weight: 700;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 2px;
  margin-bottom: 12px;
}

.event-name {
  font-size: 22px;
  font-weight: 800;
  letter-spacing: -0.5px;
  margin-bottom: 8px;
}

.event-location {
  font-size: 14px;
  color: var(--text-muted);
  display: flex;
  align-items: center;
  gap: 6px;
}

.event-emoji { font-size: 20px; }

/* REGIONS */
.regions-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 20px;
}

.region-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 28px;
  transition: transform 0.2s;
}

.region-card:hover { transform: translateY(-4px); }

.region-flag {
  font-size: 32px;
  margin-bottom: 16px;
}

.region-name {
  font-size: 18px;
  font-weight: 800;
  margin-bottom: 12px;
  letter-spacing: -0.5px;
}

.region-teams {
  list-style: none;
}

.region-teams li {
  font-size: 14px;
  color: var(--text-muted);
  padding: 6px 0;
  border-bottom: 1px solid var(--border);
  font-weight: 500;
}

.region-teams li:last-child { border-bottom: none; }

/* SCHEDULE */
.schedule-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.schedule-item {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 20px 28px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 12px;
  transition: border-color 0.2s;
}

.schedule-item:hover { border-color: var(--accent); }

.schedule-date {
  font-size: 13px;
  color: var(--accent);
  font-weight: 700;
  min-width: 140px;
}

.schedule-name {
  font-size: 16px;
  font-weight: 700;
  flex: 1;
}

.schedule-location {
  font-size: 13px;
  color: var(--text-muted);
  font-weight: 600;
}

.badge {
  background: rgba(249,115,22,0.15);
  color: var(--accent);
  padding: 4px 12px;
  border-radius: 50px;
  font-size: 12px;
  font-weight: 700;
}

.badge.blue {
  background: rgba(59,130,246,0.15);
  color: var(--accent2);
}

/* PRIZE */
.prize-section {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 60px 48px;
  text-align: center;
  position: relative;
  overflow: hidden;
}

.prize-section::before {
  content: '';
  position: absolute;
  bottom: -100px;
  right: -100px;
  width: 400px;
  height: 400px;
  background: radial-gradient(circle, rgba(249,115,22,0.08) 0%, transparent 70%);
  pointer-events: none;
}

.prize-amount {
  font-size: clamp(56px, 8vw, 96px);
  font-weight: 900;
  letter-spacing: -4px;
  color: var(--accent);
  line-height: 1;
  margin-bottom: 16px;
}

.prize-label {
  font-size: 18px;
  color: var(--text-muted);
  font-weight: 600;
}

.prize-detail {
  margin-top: 32px;
  display: flex;
  justify-content: center;
  gap: 40px;
  flex-wrap: wrap;
}

.prize-detail-item {
  text-align: center;
}

.prize-detail-num {
  font-size: 28px;
  font-weight: 800;
  letter-spacing: -1px;
}

.prize-detail-desc {
  font-size: 13px;
  color: var(--text-muted);
  font-weight: 600;
  margin-top: 4px;
}

/* FOOTER */
footer {
  border-top: 1px solid var(--border);
  padding: 48px 40px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 16px;
}

.footer-logo {
  font-size: 18px;
  font-weight: 900;
}

.footer-logo span { color: var(--accent); }

.footer-text {
  font-size: 13px;
  color: var(--text-muted);
}

/* DIVIDER */
.divider {
  height: 1px;
  background: var(--border);
  max-width: 1100px;
  margin: 0 auto;
}

/* ── MOBILE : 768px 이하 ───────────────────────────── */
@media (max-width: 768px) {
  nav { padding: 14px 24px; }
  .section { padding: 72px 20px; }
  .stats { padding: 60px 20px; gap: 16px; }
  .prize-section { padding: 48px 32px; }
  footer { padding: 40px 24px; }
}

/* ── MOBILE : 480px 이하 ───────────────────────────── */
@media (max-width: 480px) {

  /* NAV */
  nav { padding: 12px 16px; }
  .nav-links { display: none; }
  .nav-cta { padding: 8px 14px; font-size: 13px; }

  /* HERO */
  .hero { padding: 88px 16px 56px; }
  .hero h1 { letter-spacing: -1px; line-height: 1.1; }
  .hero p { font-size: 15px; margin-bottom: 36px; }
  .hero-buttons { flex-direction: column; width: 100%; max-width: 300px; }
  .btn-primary,
  .btn-secondary {
    width: 100%;
    text-align: center;
    padding: 14px 24px;
    font-size: 15px;
  }

  /* STATS */
  .stats {
    grid-template-columns: repeat(2, 1fr);
    padding: 40px 16px;
    gap: 10px;
  }
  .stat-card { padding: 22px 18px; }
  .stat-number { font-size: 32px; letter-spacing: -1px; }
  .stat-label { font-size: 13px; }

  /* SECTIONS */
  .section { padding: 52px 16px; }
  .section-title { letter-spacing: -1px; }
  .section-desc { font-size: 15px; margin-bottom: 28px; }

  /* EVENTS */
  .events-grid { grid-template-columns: 1fr; }
  .event-card { padding: 24px 20px; }
  .event-name { font-size: 19px; }

  /* REGIONS */
  .regions-grid { grid-template-columns: repeat(2, 1fr); gap: 10px; }
  .region-card { padding: 18px 14px; }
  .region-flag { font-size: 26px; margin-bottom: 10px; }
  .region-name { font-size: 14px; margin-bottom: 8px; }
  .region-teams li { font-size: 12px; padding: 5px 0; }

  /* SCHEDULE */
  .schedule-item {
    flex-direction: column;
    align-items: flex-start;
    padding: 16px 18px;
    gap: 4px;
  }
  .schedule-date { min-width: unset; font-size: 12px; }
  .schedule-name { font-size: 15px; }
  .schedule-location { font-size: 12px; }

  /* PRIZE */
  .prize-section { padding: 36px 20px; }
  .prize-amount { letter-spacing: -2px; }
  .prize-label { font-size: 14px; }
  .prize-detail { gap: 16px; margin-top: 24px; }
  .prize-detail-num { font-size: 22px; letter-spacing: -0.5px; }
  .prize-detail-desc { font-size: 12px; }

  /* FOOTER */
  footer {
    padding: 32px 16px;
    flex-direction: column;
    align-items: center;
    text-align: center;
    gap: 10px;
  }
  .footer-text { font-size: 12px; }
}

/* SCROLL ANIMATION */
.fade-up {
  opacity: 0;
  transform: translateY(30px);
  transition: opacity 0.6s ease, transform 0.6s ease;
}

.fade-up.visible {
  opacity: 1;
  transform: translateY(0);
}
